 12→    /**
 13→     * 通过 GCE Metadata Server 获取 Service Account 的 access token。
 14→     * 参考：https://docs.cloud.google.com/vertex-ai/generative-ai/docs/samples/generativeaionvertexai-gemini-chat-completions-function-calling-config
 15→     */
 16→    private function getAccessToken(): string
 17→    {
 18→        $url = 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token';
 19→        $context = stream_context_create([
 20→            'http' => [
 21→                'header' => 'Metadata-Flavor: Google',
 22→                'timeout' => 5,
 23→            ],
 24→        ]);
 25→
 26→        $response = @file_get_contents($url, false, $context);
 27→        if ($response === false) {
 28→            Log::error('[AiAnalysis] failed to get access token from metadata server');
 29→
 30→            return '';
 31→        }
 32→
 33→        $data = json_decode($response, true);
 34→
 35→        return $data['access_token'] ?? '';
 36→    }
 37→
 38→    /**
 39→     * Blocking 模式：调用 Vertex AI，返回完整分析结果。
 40→     * 用于邮件发送场景。
 41→     */
 42→    public function analyze(string $content, string $systemPrompt): string
 43→    {
 44→        [$endpoint, $model] = $this->getVertexConfig();
 45→        $accessToken = $this->getAccessToken();
 46→
 47→        if (empty($accessToken)) {
 48→            Log::error('[AiAnalysis] empty access token, abort');
 49→
 50→            return '';
 51→        }
 52→
 53→        $payload = json_encode([
 54→            'model' => $model,
 55→            'messages' => [
 56→                ['role' => 'system', 'content' => $systemPrompt],
 57→                ['role' => 'user', 'content' => $content],
 58→            ],
 59→            'stream' => false,
 60→        ], JSON_UNESCAPED_UNICODE);
 61→
 62→        Log::info('[AiAnalysis] blocking request', [
 63→            'content_len' => mb_strlen($content),
 64→            'prompt_len' => mb_strlen($systemPrompt),
 65→        ]);
 66→
 67→        $ch = curl_init($endpoint);
 68→        curl_setopt_array($ch, [
 69→            CURLOPT_POST => true,
 70→            CURLOPT_POSTFIELDS => $payload,
 71→            CURLOPT_HTTPHEADER => [
 72→                'Content-Type: application/json',
 73→                'Authorization: Bearer '.$accessToken,
 74→            ],
 75→            CURLOPT_RETURNTRANSFER => true,
 76→            CURLOPT_TIMEOUT => 120,
 77→        ]);
 78→
 79→        $response = curl_exec($ch);
 80→        $httpCode = curl_getinfo($ch, CURLINFO_HTTP_CODE);
 81→        $curlError = $response === false ? curl_error($ch) : '';
 82→        curl_close($ch);
 83→
 84→        if ($curlError) {
 85→            Log::error('[AiAnalysis] curl error', ['error' => $curlError]);
 86→            return '';
 87→        }
 88→
 89→        $result = json_decode($response, true);
 90→        if (!is_array($result)) {
 91→            Log::error('[AiAnalysis] invalid response', ['raw' => mb_substr($response, 0, 1000)]);
 92→            return '';
 93→        }
 94→
 95→        $answer = Arr::get($result, 'choices.0.message.content', '');
 96→        Log::info('[AiAnalysis] blocking done', ['answer_len' => mb_strlen($answer)]);
 97→
 98→        return $answer;
 99→    }
