101→    /**
102→     * Streaming 模式：调用 Vertex AI，通过回调逐 chunk 输出。
103→     * 用于测试 Prompt 和前端 SSE 场景。
104→     *
105→     * @param string $content 日报内容
106→     * @param string $systemPrompt AI Prompt
107→     * @param callable $onChunk fn(string $chunk): void 每个 chunk 的回调
108→     * @param array $history 可选的历史对话消息
109→     */
110→    public function analyzeStream(string $content, string $systemPrompt, callable $onChunk, array $history = []): string
111→    {
112→        [$endpoint, $model] = $this->getVertexConfig();
113→        $accessToken = $this->getAccessToken();
114→
115→        if (empty($accessToken)) {
116→            Log::error('[AiAnalysis] empty access token, abort streaming');
117→
118→            return '';
119→        }
120→
121→        $messages = [
122→            ['role' => 'system', 'content' => $systemPrompt],
123→        ];
124→        foreach ($history as $msg) {
125→            $messages[] = ['role' => $msg['role'], 'content' => $msg['content']];
126→        }
127→        if (!empty($content)) {
128→            $messages[] = ['role' => 'user', 'content' => $content];
129→        }
130→
131→        $payload = json_encode([
132→            'model' => $model,
133→            'messages' => $messages,
134→            'stream' => true,
135→        ], JSON_UNESCAPED_UNICODE);
136→
137→        Log::info('[AiAnalysis] streaming request', [
138→            'content_len' => mb_strlen($content),
139→            'prompt_len' => mb_strlen($systemPrompt),
140→            'history_count' => count($history),
141→        ]);
142→
143→        $fullReply = '';
144→        $buffer = '';
145→
146→        $ch = curl_init($endpoint);
147→        curl_setopt_array($ch, [
148→            CURLOPT_POST => true,
149→            CURLOPT_POSTFIELDS => $payload,
150→            CURLOPT_HTTPHEADER => [
151→                'Content-Type: application/json',
152→                'Authorization: Bearer '.$accessToken,
153→            ],
154→            CURLOPT_RETURNTRANSFER => false,
155→            CURLOPT_TIMEOUT => 300,
156→            CURLOPT_WRITEFUNCTION => function ($curl, $data) use (&$fullReply, &$buffer, $onChunk) {
157→                $buffer .= $data;
158→
159→                while (($pos = strpos($buffer, "\n")) !== false) {
160→                    $line = rtrim(substr($buffer, 0, $pos), "\r");
161→                    $buffer = substr($buffer, $pos + 1);
162→
163→                    if (!str_starts_with($line, 'data: ')) {
164→                        continue;
165→                    }
166→
167→                    $jsonStr = substr($line, 6);
168→                    if ($jsonStr === '[DONE]') {
169→                        continue;
170→                    }
171→
172→                    $decoded = json_decode($jsonStr, true);
173→                    if (!is_array($decoded)) {
174→                        continue;
175→                    }
176→
177→                    $chunk = Arr::get($decoded, 'choices.0.delta.content', '');
178→                    if ($chunk !== '') {
179→                        $fullReply .= $chunk;
180→                        $onChunk($chunk);
181→                    }
182→                }
183→
184→                return strlen($data);
185→            },
186→        ]);
187→
188→        curl_exec($ch);
189→        $curlError = curl_error($ch);
190→        curl_close($ch);
191→
192→        if ($curlError) {
193→            Log::error('[AiAnalysis] streaming curl error', ['error' => $curlError]);
194→        }
195→
196→        Log::info('[AiAnalysis] streaming done', ['reply_len' => mb_strlen($fullReply)]);
197→
198→        return $fullReply;
199→    }
200→
201→    /**
202→     * 拼接 Vertex AI OpenAI 兼容端点并返回配置。
203→     * 端点格式：https://{LOCATION}-aiplatform.googleapis.com/v1beta1/projects/{PROJECT_ID}/locations/{LOCATION}/endpoints/openapi/chat/completions
204→     */
205→    private function getVertexConfig(): array
206→    {
207→        $projectId = config('vertex_ai.project_id');
208→        $location = config('vertex_ai.location', 'us-central1');
209→        $model = config('vertex_ai.model', 'google/gemini-2.0-flash-001');
210→
211→        $endpoint = "https://{$location}-aiplatform.googleapis.com/v1beta1/projects/{$projectId}/locations/{$location}/endpoints/openapi/chat/completions";
212→
213→        return [$endpoint, $model];
214→    }
215→}
