 38→    /**
 39→     * 发送密文邮件，检查接收者的权限。
 40→     *
 41→     * @param \Illuminate\Http\Request $request
 42→     *
 43→     * @throws \App\Exceptions\UserException
 44→     * @throws \App\Exceptions\IOException
 45→     * @throws \App\Exceptions\ServerException
 46→     * @throws \App\Exceptions\CryptoException
 47→     * @throws \App\Exceptions\CommonException
 48→     * @return \Illuminate\Http\JsonResponse
 49→     */
 50→    public function sendDecr(Request $request): JsonResponse
 51→    {
 52→        Headers::$customLineLength = 512; // 调整 Header 长度
 53→        $params = $request->all();
 54→        $conf = $params['decrypt_config'];
 55→        unset($params['decrypt_config']);
 56→
 57→        $aiAnalysisConfig = $params['ai_analysis_config'] ?? null;
 58→        unset($params['ai_analysis_config']);
 59→
 60→        // 通过 receivers 参数解析出接收者的邮箱
 61→        [$rcvEmails, $receivers] = AuthorizeService::app()->retrieveEmailsOfReceivers($params['receivers']);
 62→        unset($params['receivers']);
 63→
 64→        // 解密并检查是否所有收件人都有所有密文的权限，解密出错时直接抛出异常，不发邮件
 65→        $conf['receivers'] = $receivers;
 66→        $params = DecryptService::app()->throwEcp()->decryptData($params, $conf, 'send_email');
 67→
 68→        // 如果配置了 AI 分析，对邮件内容进行分析并将摘要插入邮件头部
 69→        if (!empty($aiAnalysisConfig) && !empty($aiAnalysisConfig['system_prompt'])) {
 70→            Log::info('[lbl][0416-AI日报][Mail][AI] 开始AI分析邮件内容', [
 71→                'content_len' => mb_strlen($params['content']),
 72→                'prompt_len' => mb_strlen($aiAnalysisConfig['system_prompt']),
 73→                'receivers' => $rcvEmails,
 74→            ]);
 75→            $aiResult = AiAnalysisService::app()->analyze(
 76→                $params['content'],
 77→                $aiAnalysisConfig['system_prompt']
 78→            );
 79→            if (!empty($aiResult)) {
 80→                Log::info('[lbl][0416-AI日报][Mail][AI] AI分析完成, 摘要已插入邮件', ['result_len' => mb_strlen($aiResult)]);
 81→                $params['content'] = '<div style="background:#f0f7ff;padding:16px;border-radius:8px;margin-bottom:20px;">'
 82→                    .'<h3 style="margin:0 0 12px 0;">📊 AI 分析摘要</h3>'
 83→                    .'<div>'.nl2br(e($aiResult)).'</div>'
 84→                    .'</div>'
 85→                    .'<hr style="margin:20px 0;">'
 86→                    .$params['content'];
 87→            }
 88→        }
 89→
 90→        $mail = new BlankMail($params['content']);
 91→        $mail->subject($params['subject']);
 92→        $mail->to($rcvEmails);
 93→
 94→        if (!empty($params['attachments'])) {
 95→            // 处理附件，根据真实文件名找到文件的存储路径
 96→            foreach ($params['attachments'] as $one) {
 97→                $filePath = FileService::app()->getRealFile($one['path'], $one['disk']);
 98→                $realName = $one['real_name'] ?? $one['path'];
 99→                // 为了支持 QQ 邮箱中文附件名过长时的显示和下载乱码问题，注意上面重载了 Header 长度
100→                // 这样可以保证 header 里面的附件名不被分隔，相关 rfc：2184，2231，2047
101→                // @see https://github.com/jstedfast/MimeKit/blob/master/FAQ.md#q-why-do-attachments-with-unicode-or-long-filenames-appear-as-att0dat-in-outlook
102→                $mail->attach($filePath, [
103→                    'as' => '=?UTF-8?B?'.base64_encode($realName).'?=',
104→                ]);
105→            }
106→        }
107→
108→        Mail::send($mail);
109→        return $this->responseJsonSuccess(['success' => true]);
110→    }
111→}
